eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   COMPLETION_TIPS: () => (/* binding */ COMPLETION_TIPS),\n/* harmony export */   HADITHS: () => (/* binding */ HADITHS),\n/* harmony export */   getCompletionTip: () => (/* binding */ getCompletionTip),\n/* harmony export */   getDailyHadith: () => (/* binding */ getDailyHadith),\n/* harmony export */   getRandomHadith: () => (/* binding */ getRandomHadith)\n/* harmony export */ });\n// ---------------------------------------------------------------------------\n// Hadith & Islamic tips database (Task 17 – Educational Pop-ups)\n// Sources: Sahih Bukhari, Muslim, Abu Dawud, Tirmidhi, Riyadh Al-Salihin\n// ---------------------------------------------------------------------------\nconst HADITHS = [\n    // --- Prayer ---\n    {\n        id: 1,\n        text: \"الصَّلَوَاتُ الخَمْسُ، وَالجُمُعَةُ إِلى الجُمُعَةِ كَفَّارَةٌ لِما بَيْنَهُنَّ مَا لَمْ تُغْشَ الكَبَائِرُ\",\n        source: \"صحيح مسلم\",\n        category: \"prayer\"\n    },\n    {\n        id: 2,\n        text: \"أَوَّلُ ما يُحَاسَبُ عليه العَبْدُ يَوْمَ القِيَامَةِ الصَّلَاةُ، فإن صَلَحَتْ صَلَحَ سَائِرُ عَمَلِهِ\",\n        source: \"الطبراني\",\n        category: \"prayer\"\n    },\n    {\n        id: 3,\n        text: \"مَن حَافَظَ عَلَيها كانَتْ لَهُ نُورًا وبُرهانًا ونَجاةً يَوْمَ القِيامَةِ\",\n        source: \"مسند أحمد\",\n        category: \"prayer\"\n    },\n    {\n        id: 4,\n        text: \"ارْكَعْ رَكْعَتَيْنِ إِذَا أَذْنَبْتَ، فَإِنَّ الرَّكْعَتَيْنِ تَمْحُوانِ الذَّنْبَ\",\n        source: \"المعجم الكبير\",\n        category: \"prayer\"\n    },\n    {\n        id: 5,\n        text: \"إذا قام أحدكم إلى الصلاة فلا يمسح الحصى، فإن الرحمة تواجهه\",\n        source: \"سنن أبي داود\",\n        category: \"prayer\"\n    },\n    // --- Quran ---\n    {\n        id: 6,\n        text: \"اقْرَؤُوا القُرآنَ فإنَّهُ يَأتي يَوْمَ القِيامةِ شَفِيعًا لأصْحابِهِ\",\n        source: \"صحيح مسلم\",\n        category: \"quran\"\n    },\n    {\n        id: 7,\n        text: \"الماهِرُ بالقُرآنِ مَعَ السَّفَرةِ الكِرامِ البَرَرةِ، والَّذي يَقرَأُ القُرآنَ ويَتَتَعتَعُ فيه وهو عليه شاقٌّ له أجْران\",\n        source: \"صحيح البخاري\",\n        category: \"quran\"\n    },\n    {\n        id: 8,\n        text: \"خَيرُكُم مَن تَعَلَّمَ القُرآنَ وعَلَّمَهُ\",\n        source: \"صحيح البخاري\",\n        category: \"quran\"\n    },\n    {\n        id: 9,\n        text: \"إنَّ الذي ليس في جَوفِه شيءٌ من القُرآنِ كالبيتِ الخَرِبِ\",\n        source: \"جامع الترمذي\",\n        category: \"quran\"\n    },\n    // --- Azkar / Dhikr ---\n    {\n        id: 10,\n        text: \"أَلا بِذِكرِ اللَّهِ تَطمَئِنُّ القُلُوبُ\",\n        source: \"القرآن الكريم – الرعد: ٢٨\",\n        category: \"azkar\"\n    },\n    {\n        id: 11,\n        text: \"كَلِمَتَانِ خَفِيفَتَانِ عَلَى اللِّسَانِ، ثَقِيلَتَانِ فِي الميزانِ، حَبِيبَتَانِ إِلَى الرَّحْمَنِ: سُبْحَانَ اللَّهِ وَبِحَمْدِهِ، سُبْحَانَ اللَّهِ العَظِيمِ\",\n        source: \"صحيح البخاري\",\n        category: \"azkar\"\n    },\n    {\n        id: 12,\n        text: \"مَن سَبَّحَ اللهَ في دُبُرِ كُلِّ صَلاةٍ ثَلاثًا وثَلاثِينَ، وحَمِدَ اللهَ ثَلاثًا وثَلاثِينَ، وكَبَّرَ اللهَ ثَلاثًا وثَلاثِينَ... غُفِرَتْ خَطاياهُ\",\n        source: \"صحيح مسلم\",\n        category: \"azkar\"\n    },\n    {\n        id: 13,\n        text: \"مَن قالَ: سُبحانَ اللهِ وبِحَمدِهِ في يَومٍ مِئةَ مَرَّةٍ، حُطَّتْ خَطاياهُ وإن كانَتْ مِثلَ زَبَدِ البَحرِ\",\n        source: \"صحيح البخاري\",\n        category: \"azkar\"\n    },\n    // --- Fasting ---\n    {\n        id: 14,\n        text: \"مَن صامَ يَومًا في سَبِيلِ اللَّهِ بَعَّدَ اللَّهُ وَجهَهُ عَن النَّارِ سَبعِينَ خَرِيفًا\",\n        source: \"متفق عليه\",\n        category: \"fasting\"\n    },\n    {\n        id: 15,\n        text: \"الصِّيامُ جُنَّةٌ، فلا يَرفُثْ ولا يَجهَلْ، وإنِ امرُؤٌ قاتَلَهُ أو شاتَمَهُ فَلْيَقُلْ: إنِّي صائِمٌ\",\n        source: \"صحيح البخاري\",\n        category: \"fasting\"\n    },\n    // --- Family ---\n    {\n        id: 16,\n        text: \"مَن سَرَّهُ أن يُبسَطَ له في رِزقِهِ، ويُنسَأَ له في أثَرِهِ، فَلْيَصِلْ رَحِمَهُ\",\n        source: \"صحيح البخاري\",\n        category: \"family\"\n    },\n    {\n        id: 17,\n        text: \"الرَّاحِمُونَ يَرحَمُهُمُ الرَّحمَنُ، ارحَمُوا مَن في الأَرضِ يَرحَمكُم مَن في السَّماءِ\",\n        source: \"جامع الترمذي\",\n        category: \"family\"\n    },\n    {\n        id: 18,\n        text: \"لَيسَ الواصِلُ بالمُكافِئِ، ولكنَّ الواصِلَ الَّذي إذا قُطِعَت رَحِمُهُ وَصَلَها\",\n        source: \"صحيح البخاري\",\n        category: \"family\"\n    },\n    // --- General ---\n    {\n        id: 19,\n        text: \"احرِصْ على ما يَنفَعُك واستَعِنْ باللهِ ولا تَعجَزْ\",\n        source: \"صحيح مسلم\",\n        category: \"general\"\n    },\n    {\n        id: 20,\n        text: \"إنَّ اللهَ يُحِبُّ إذا عَمِلَ أَحَدُكُم عَمَلًا أَن يُتقِنَهُ\",\n        source: \"البيهقي\",\n        category: \"general\"\n    },\n    {\n        id: 21,\n        text: \"المُؤمِنُ القَوِيُّ خَيرٌ وأَحَبُّ إِلى اللهِ مِنَ المُؤمِنِ الضَّعِيفِ\",\n        source: \"صحيح مسلم\",\n        category: \"general\"\n    },\n    {\n        id: 22,\n        text: \"تَبَسُّمُكَ في وَجهِ أَخِيكَ صَدَقَةٌ\",\n        source: \"جامع الترمذي\",\n        category: \"general\"\n    },\n    {\n        id: 23,\n        text: \"مَا نَقَصَت صَدَقَةٌ مِن مَالٍ\",\n        source: \"صحيح مسلم\",\n        category: \"general\"\n    },\n    {\n        id: 24,\n        text: \"إيَّاكُم والحَسَدَ، فإنَّ الحَسَدَ يَأكُلُ الحَسَناتِ كما تَأكُلُ النَّارُ الحَطَبَ\",\n        source: \"سنن أبي داود\",\n        category: \"general\"\n    },\n    {\n        id: 25,\n        text: \"مَن كانَ يُؤمِنُ باللهِ واليَومِ الآخِرِ فَلْيَقُلْ خَيرًا أَو لِيَصمُتْ\",\n        source: \"متفق عليه\",\n        category: \"general\"\n    }\n];\n// Tips shown after completing different worship tasks\nconst COMPLETION_TIPS = {\n    prayer: [\n        \"تقبّل الله منك! الصلاة نور ✨\",\n        \"بارك الله في محافظتك على الصلاة \\uD83C\\uDF19\",\n        \"المحافظة على الصلاة طريق النجاة \\uD83C\\uDF3F\",\n        \"ما شاء الله! الصلاة في وقتها أحب الأعمال إلى الله \\uD83D\\uDCA1\",\n        \"جعل الله صلاتك قرة عين لك \\uD83E\\uDD32\",\n        \"أحسنت! الصلاة عماد الدين \\uD83C\\uDFDB️\",\n        \"من حافظ عليها كانت له نورًا وبرهانًا ونجاةً يوم القيامة \\uD83C\\uDF1F\",\n        \"الصلاة تنهى عن الفحشاء والمنكر — استمر على هذا الطريق \\uD83D\\uDEE4️\",\n        \"بارك الله في يومك! الصلاة خير موضوع \\uD83C\\uDF19\",\n        \"تقبّل الله صلاتك وجعلها في ميزان حسناتك ⚖️\"\n    ],\n    quran: [\n        \"بارك الله في تلاوتك \\uD83D\\uDCD6\",\n        \"كل حرف تقرأه بعشر حسنات ✨\",\n        \"القرآن شفاء للقلوب \\uD83D\\uDC9A\",\n        \"اقرأوا القرآن فإنّه يأتي يوم القيامة شفيعًا لأصحابه \\uD83C\\uDF1F\",\n        \"خيركم من تعلّم القرآن وعلّمه \\uD83D\\uDCAA\",\n        \"جعل الله القرآن ربيع قلبك ونور صدرك \\uD83C\\uDF33\",\n        \"تقبّل الله تلاوتك ونفعك به \\uD83E\\uDD32\",\n        \"استمر! المداومة على قراءة القرآن مفتاح البركة \\uD83D\\uDD11\",\n        \"الماهر بالقرآن مع السفرة الكرام البررة \\uD83C\\uDF08\",\n        \"حرف بحرف تُبنى شخصية المسلم المحب لكتاب الله ❤️\"\n    ],\n    azkar: [\n        \"أحسنت! الذكر طمأنينة القلب \\uD83D\\uDCFF\",\n        \"السبحة الذهبية لمن يداوم على الذكر ⭐\",\n        \"بارك الله فيك على محافظتك على الأذكار \\uD83C\\uDF1F\",\n        \"ألا بذكر الله تطمئن القلوب — واضحٌ في حياتك \\uD83C\\uDF4C\",\n        \"كلمتان خفيفتان على اللسان ثقيلتان في الميزان: سبحان الله وبحمده \\uD83C\\uDF20\",\n        \"بداية اليوم بالذكر تجعله يومًا مباركًا ☄️\",\n        \"الله يجزيك خيرًا على كل تسبيحة \\uD83C\\uDF3C\",\n        \"الذكر بعد الصلاة كنز المؤمن \\uD83D\\uDCB0\",\n        \"تقبّل الله أذكارك \\uD83E\\uDD32\",\n        \"من سبّح الله مئة مرة حُطّت خطاياه وإن كانت مثل زبد البحر \\uD83C\\uDF0A\"\n    ],\n    fasting: [\n        \"الصيام جُنّة ودرع من النار \\uD83D\\uDEE1️\",\n        \"تقبّل الله صيامك \\uD83E\\uDD32\",\n        \"للصائم فرحتان: فرحة عند فطره وفرحة عند لقاء ربه \\uD83D\\uDE0A\",\n        \"من صام يومًا في سبيل الله بعّد الله وجهه عن النار سبعين خريفًا \\uD83C\\uDF4B\",\n        \"الصوم يشفع لصاحبه يوم القيامة \\uD83C\\uDF1F\",\n        \"بارك الله في صبرك وتقواك \\uD83C\\uDF3F\",\n        \"ومن صام رمضان إيمانًا واحتسابًا غُفر له ما تقدّم من ذنبه \\uD83D\\uDC9A\",\n        \"الصيام والقرآن يشفعان للعبد يوم القيامة ⚖️\",\n        \"أحسنت! الصوم لي وأنا أجزي به — الله عز وجل \\uD83C\\uDF1F\",\n        \"فطرك على تمرة سنة نبوية \\uD83C\\uDF7C\"\n    ],\n    challenge: [\n        \"ما شاء الله! استمر في التحدي \\uD83D\\uDCAA\",\n        \"الإصرار على العمل الصالح من أحب الأعمال إلى الله \\uD83C\\uDF1F\",\n        \"خطوة بخطوة تُبنى العادات الصالحة \\uD83C\\uDFC6\",\n        \"العائلة تشجعك — لا تئيسوا من روح الله \\uD83D\\uDC9A\",\n        \"كل يوم تكمله في التحدي هو انتصار \\uD83C\\uDFC5\",\n        \"بارك الله فيك! هذا التحدي يرفعك درجات عند ربك ⚡\",\n        \"من جدّ وجد — استمر \\uD83D\\uDD25\",\n        \"أحسنت! استمرارك في التحدي يلهم الآخرين \\uD83E\\uDD1D\",\n        \"كل خطوة في سبيل الله محسوبة لك \\uD83E\\uDD32\",\n        \"التحدي شارفك على طريق الجنة ✨\"\n    ],\n    general: [\n        \"بارك الله فيك! خطوة جميلة نحو الاستمرار \\uD83D\\uDC9A\",\n        \"أحسنت! استمر على فعل الخير \\uD83C\\uDF1F\",\n        \"تقبّل الله منك عملك الصالح \\uD83E\\uDD32\",\n        \"إنّ الله يحب إذا عمل أحدكم عملاً أن يُتقنه ⭐\",\n        \"كل يوم تكون أحسن مما كنت عليه بالأمس \\uD83D\\uDCC8\",\n        \"العائلة والتزكية هما أساس السعادة \\uD83C\\uDFE1\",\n        \"احرص على ما ينفعك واستعن بالله \\uD83D\\uDCAA\",\n        \"تبسّمك في وجه أخيك صدقة \\uD83D\\uDE0A\",\n        \"المؤمن القويّ خير وأحب إلى الله \\uD83E\\uDDD8\",\n        \"في كل خطوة خير فرجة لصدرك - بارك الله فيك ❤️\"\n    ]\n};\n/**\r\n * Get a random hadith, optionally filtered by category.\r\n */ function getRandomHadith(category) {\n    const pool = category ? HADITHS.filter((h)=>h.category === category) : HADITHS;\n    return pool[Math.floor(Math.random() * pool.length)];\n}\n/**\r\n * Get a deterministic daily hadith based on today's date.\r\n */ function getDailyHadith() {\n    const dayOfYear = Math.floor((Date.now() - new Date(new Date().getFullYear(), 0, 0).getTime()) / 86400000);\n    return HADITHS[dayOfYear % HADITHS.length];\n}\n/**\r\n * Get a random completion tip for a given activity type.\r\n */ function getCompletionTip(type = \"general\") {\n    const pool = COMPLETION_TIPS[type] ?? COMPLETION_TIPS.general;\n    return pool[Math.floor(Math.random() * pool.length)];\n}\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/lib/hadith.ts\n");

